input.content:
type Result = { premium: number } | { payout: number; remainingCap: number };

type Item = { type: string; material: string; enchantment: number; cursed: boolean };
type Step = { op: string; items?: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

export const processScenario = (scenario: unknown): { results: Result[] } => {
  const s = scenario as Scenario;
  const results: Result[] = [];

  for (const step of s.steps) {
    if (step.op === "quote") {
      let base = 0;
      for (const item of step.items ?? []) {
        base += BASE_PREMIUMS[item.type] ?? 0;
      }
      const premium = Math.floor(base * 1.1) + 5;
      results.push({ premium });
    }
  }

  return { results };
};

