  const results: Result[] = [];
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      let basePremium = 0;
      for (const item of step.items ?? []) {
        basePremium += BASE_PREMIUMS[item.type] ?? 0;
      }
      const premium = Math.floor(basePremium * 1.1) + 5;
      results.push({ premium });
    }
  }
  return { results };
};
```

