            { type: "sword", material: "steel", enchantment: 3, cursed: true },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 170 }] });
  });
  it.todo("should process a basic claim deducting the 100 G deductible");
  it.todo("should track remaining cap after a claim");
});

