export const processScenario = (scenario: Scenario): { results: Result[] } => {
  const results: Result[] = [];
  const policies: Policy[] = [];

  scenario.steps.forEach((step, i) => {
    if (step.op === "quote") {
      let basePremium = 0;
      let insuranceSum = 0;
      for (const item of step.items ?? []) {
